// Flat ESLint config (ESLint v9+)
// Reads ignore patterns from build/config/ignore.eslint.json (generated by sync-ignores.js)

import fs from 'node:fs';
import path from 'node:path';
import js from '@eslint/js';

const ROOT = path.resolve(new URL('.', import.meta.url).pathname, '../../..');
const CONFIG_DIR = path.join(ROOT, 'build', 'config');
const ignoreJsonPath = path.join(CONFIG_DIR, 'ignore.eslint.json');

let ignorePatterns = [];
try {
  const raw = fs.readFileSync(ignoreJsonPath, 'utf8');
  ignorePatterns = JSON.parse(raw).ignorePatterns || [];
} catch {
  // if missing, proceed with empty ignores
}

export default [
  {
    name: 'root',
    ignores: ignorePatterns,
  },
  js.configs.recommended,
  {
    files: ['**/*.js', '**/*.mjs', '**/*.cjs'],
    languageOptions: {
      ecmaVersion: 'latest',
      sourceType: 'commonjs',
    },
    rules: {
      // your project rules here
      'no-empty': ['error', { allowEmptyCatch: true }],
    },
  },
];
